import { z } from 'zod';
import type { Prisma } from '@prisma/client';

/////////////////////////////////////////
// HELPER FUNCTIONS
/////////////////////////////////////////


/////////////////////////////////////////
// ENUMS
/////////////////////////////////////////

export const TransactionIsolationLevelSchema = z.enum(['ReadUncommitted','ReadCommitted','RepeatableRead','Serializable']);

export const UserScalarFieldEnumSchema = z.enum(['id','name','avatarPlayerId','recoveryKey','nameUpdatedAt','avatarUpdatedAt','createdAt','updatedAt']);

export const TeamScalarFieldEnumSchema = z.enum(['id','externalId','name','code','region','flagUrl','createdAt','updatedAt']);

export const PlayerScalarFieldEnumSchema = z.enum(['id','externalId','teamId','name','photoUrl','position','createdAt','updatedAt']);

export const MatchScalarFieldEnumSchema = z.enum(['id','externalId','homeTeamId','awayTeamId','winnerTeamId','phase','status','startsAt','scoreHome','scoreAway','createdAt','updatedAt']);

export const MatchPredictionScalarFieldEnumSchema = z.enum(['id','userId','matchId','predictedHome','predictedAway','points','exactHit','result','createdAt']);

export const TournamentPredictionScalarFieldEnumSchema = z.enum(['id','userId','championTeamId','runnerUpTeamId','finalHomeTeamId','finalAwayTeamId','surpriseTeamId','disappointmentTeamId','mvpPlayerId','goldenBootPlayerId','bestGoalkeeperPlayerId','revelationPlayerId','points','createdAt']);

export const TournamentResultScalarFieldEnumSchema = z.enum(['id','championTeamId','runnerUpTeamId','finalHomeTeamId','finalAwayTeamId','surpriseTeamId','disappointmentTeamId','mvpPlayerId','goldenBootPlayerId','bestGoalkeeperPlayerId','revelationPlayerId','createdAt','updatedAt']);

export const LeaderboardDailyScalarFieldEnumSchema = z.enum(['id','userId','totalPoints','exactHits','rank','previousRank','rankDelta','calculatedAt']);

export const ApiSyncLogScalarFieldEnumSchema = z.enum(['id','endpoint','statusCode','success','message','requestsUsed','remainingQuota','syncedAt']);

export const SortOrderSchema = z.enum(['asc','desc']);

export const QueryModeSchema = z.enum(['default','insensitive']);

export const NullsOrderSchema = z.enum(['first','last']);

export const MatchPhaseSchema = z.enum(['GROUP','ROUND_OF_16','QUARTER_FINAL','SEMI_FINAL','THIRD_PLACE','FINAL']);

export type MatchPhaseType = `${z.infer<typeof MatchPhaseSchema>}`

export const MatchStatusSchema = z.enum(['SCHEDULED','FINISHED']);

export type MatchStatusType = `${z.infer<typeof MatchStatusSchema>}`

export const PlayerPositionSchema = z.enum(['GK','DEF','MID','FWD']);

export type PlayerPositionType = `${z.infer<typeof PlayerPositionSchema>}`

export const TeamRegionSchema = z.enum(['CONMEBOL','UEFA','CONCACAF','CAF','AFC','OFC']);

export type TeamRegionType = `${z.infer<typeof TeamRegionSchema>}`

export const MatchPredictionResultSchema = z.enum(['EXACT_SCORE','WINNER','DRAW','WRONG']);

export type MatchPredictionResultType = `${z.infer<typeof MatchPredictionResultSchema>}`

/////////////////////////////////////////
// MODELS
/////////////////////////////////////////

/////////////////////////////////////////
// USER SCHEMA
/////////////////////////////////////////

export const UserSchema = z.object({
  id: z.string(),
  name: z.string(),
  avatarPlayerId: z.string().nullable(),
  recoveryKey: z.string(),
  nameUpdatedAt: z.coerce.date().nullable(),
  avatarUpdatedAt: z.coerce.date().nullable(),
  createdAt: z.coerce.date(),
  updatedAt: z.coerce.date(),
})

export type User = z.infer<typeof UserSchema>

/////////////////////////////////////////
// TEAM SCHEMA
/////////////////////////////////////////

export const TeamSchema = z.object({
  region: TeamRegionSchema.nullable(),
  id: z.uuid(),
  externalId: z.string().nullable(),
  name: z.string(),
  code: z.string(),
  flagUrl: z.string(),
  createdAt: z.coerce.date(),
  updatedAt: z.coerce.date(),
})

export type Team = z.infer<typeof TeamSchema>

/////////////////////////////////////////
// PLAYER SCHEMA
/////////////////////////////////////////

export const PlayerSchema = z.object({
  position: PlayerPositionSchema,
  id: z.uuid(),
  externalId: z.string().nullable(),
  teamId: z.string(),
  name: z.string(),
  photoUrl: z.string().nullable(),
  createdAt: z.coerce.date(),
  updatedAt: z.coerce.date(),
})

export type Player = z.infer<typeof PlayerSchema>

/////////////////////////////////////////
// MATCH SCHEMA
/////////////////////////////////////////

export const MatchSchema = z.object({
  phase: MatchPhaseSchema,
  status: MatchStatusSchema,
  id: z.uuid(),
  externalId: z.string().nullable(),
  homeTeamId: z.string(),
  awayTeamId: z.string(),
  winnerTeamId: z.string().nullable(),
  startsAt: z.coerce.date(),
  scoreHome: z.number().int().nullable(),
  scoreAway: z.number().int().nullable(),
  createdAt: z.coerce.date(),
  updatedAt: z.coerce.date(),
})

export type Match = z.infer<typeof MatchSchema>

/////////////////////////////////////////
// MATCH PREDICTION SCHEMA
/////////////////////////////////////////

export const MatchPredictionSchema = z.object({
  result: MatchPredictionResultSchema.nullable(),
  id: z.uuid(),
  userId: z.string(),
  matchId: z.string(),
  predictedHome: z.number().int(),
  predictedAway: z.number().int(),
  points: z.number().int(),
  exactHit: z.boolean(),
  createdAt: z.coerce.date(),
})

export type MatchPrediction = z.infer<typeof MatchPredictionSchema>

/////////////////////////////////////////
// TOURNAMENT PREDICTION SCHEMA
/////////////////////////////////////////

export const TournamentPredictionSchema = z.object({
  id: z.uuid(),
  userId: z.string(),
  championTeamId: z.string().nullable(),
  runnerUpTeamId: z.string().nullable(),
  finalHomeTeamId: z.string().nullable(),
  finalAwayTeamId: z.string().nullable(),
  surpriseTeamId: z.string().nullable(),
  disappointmentTeamId: z.string().nullable(),
  mvpPlayerId: z.string().nullable(),
  goldenBootPlayerId: z.string().nullable(),
  bestGoalkeeperPlayerId: z.string().nullable(),
  revelationPlayerId: z.string().nullable(),
  points: z.number().int(),
  createdAt: z.coerce.date(),
})

export type TournamentPrediction = z.infer<typeof TournamentPredictionSchema>

/////////////////////////////////////////
// TOURNAMENT RESULT SCHEMA
/////////////////////////////////////////

export const TournamentResultSchema = z.object({
  id: z.uuid(),
  championTeamId: z.string().nullable(),
  runnerUpTeamId: z.string().nullable(),
  finalHomeTeamId: z.string().nullable(),
  finalAwayTeamId: z.string().nullable(),
  surpriseTeamId: z.string().nullable(),
  disappointmentTeamId: z.string().nullable(),
  mvpPlayerId: z.string().nullable(),
  goldenBootPlayerId: z.string().nullable(),
  bestGoalkeeperPlayerId: z.string().nullable(),
  revelationPlayerId: z.string().nullable(),
  createdAt: z.coerce.date(),
  updatedAt: z.coerce.date(),
})

export type TournamentResult = z.infer<typeof TournamentResultSchema>

/////////////////////////////////////////
// LEADERBOARD DAILY SCHEMA
/////////////////////////////////////////

export const LeaderboardDailySchema = z.object({
  id: z.uuid(),
  userId: z.string(),
  totalPoints: z.number().int(),
  exactHits: z.number().int(),
  rank: z.number().int(),
  previousRank: z.number().int().nullable(),
  rankDelta: z.number().int(),
  calculatedAt: z.coerce.date(),
})

export type LeaderboardDaily = z.infer<typeof LeaderboardDailySchema>

/////////////////////////////////////////
// API SYNC LOG SCHEMA
/////////////////////////////////////////

export const ApiSyncLogSchema = z.object({
  id: z.uuid(),
  endpoint: z.string(),
  statusCode: z.number().int().nullable(),
  success: z.boolean(),
  message: z.string().nullable(),
  requestsUsed: z.number().int().nullable(),
  remainingQuota: z.number().int().nullable(),
  syncedAt: z.coerce.date(),
})

export type ApiSyncLog = z.infer<typeof ApiSyncLogSchema>

